"use client";

import type {
  EditorMessageKind,
  ExportFormat,
} from "@/components/editor/types";
import { encodeWAV } from "@/utils/encodeWave";
import type { FFmpeg } from "@ffmpeg/ffmpeg";
import { useCallback, useState } from "react";
import type RegionsPlugin from "wavesurfer.js/dist/plugins/regions.esm.js";
import type WaveSurfer from "wavesurfer.js";

interface UseRingtoneExportOptions {
  ffmpegLoaded: boolean;
  ffmpegRef: React.RefObject<FFmpeg | null>;
  focusMessage: () => void;
  regionsRef: React.RefObject<RegionsPlugin | null>;
  setMessage: React.Dispatch<React.SetStateAction<string | null>>;
  setMessageKind: React.Dispatch<React.SetStateAction<EditorMessageKind>>;
  wavesurferRef: React.RefObject<WaveSurfer | null>;
}

export default function useRingtoneExport({
  ffmpegLoaded,
  ffmpegRef,
  focusMessage,
  regionsRef,
  setMessage,
  setMessageKind,
  wavesurferRef,
}: UseRingtoneExportOptions) {
  const [exportingFormat, setExportingFormat] = useState<ExportFormat | null>(
    null,
  );

  const handleExport = useCallback(
    async (format: ExportFormat) => {
      if (!wavesurferRef.current || !regionsRef.current || !ffmpegRef.current) {
        return;
      }

      const regions = regionsRef.current.getRegions();
      if (regions.length === 0) {
        setMessageKind("default");
        setMessage("Drag the highlighted region to choose the snippet.");
        return;
      }

      if (!ffmpegLoaded) {
        setMessageKind("ffmpeg-loading");
        setMessage("Audio converter is still loading. Give it a moment.");
        focusMessage();
        return;
      }

      const originalBuffer = wavesurferRef.current.getDecodedData();
      if (!originalBuffer) {
        setMessageKind("default");
        setMessage("Audio data is still preparing. Please wait a moment.");
        return;
      }

      setMessageKind("default");
      setMessage(null);
      setExportingFormat(format);

      const region = regions[0];
      const sampleRate = originalBuffer.sampleRate;
      const numChannels = originalBuffer.numberOfChannels;
      const startFrame = Math.floor(region.start * sampleRate);
      const endFrame = Math.floor(region.end * sampleRate);
      const frameCount = endFrame - startFrame;
      const interleaved = new Float32Array(frameCount * numChannels);

      for (let channel = 0; channel < numChannels; channel++) {
        const channelData = originalBuffer.getChannelData(channel);
        for (let i = 0; i < frameCount; i++) {
          interleaved[i * numChannels + channel] = channelData[startFrame + i];
        }
      }

      const wavData = encodeWAV(interleaved, sampleRate, numChannels);
      const wavUint8 = new Uint8Array(
        wavData.buffer as ArrayBuffer,
        wavData.byteOffset,
        wavData.byteLength,
      );

      try {
        const ffmpeg = ffmpegRef.current;
        await ffmpeg.writeFile("input.wav", wavUint8);

        if (format === "ios") {
          await ffmpeg.exec([
            "-i",
            "input.wav",
            "-c:a",
            "aac",
            "-b:a",
            "128k",
            "-ar",
            "44100",
            "-ac",
            "2",
            "-f",
            "ipod",
            "output.m4r",
          ]);
        } else {
          await ffmpeg.exec([
            "-i",
            "input.wav",
            "-c:a",
            "libmp3lame",
            "-b:a",
            "192k",
            "-ar",
            "44100",
            "output.mp3",
          ]);
        }

        const outputFilename = format === "ios" ? "output.m4r" : "output.mp3";
        const outputData = (await ffmpeg.readFile(outputFilename)) as Uint8Array;
        const blob = new Blob([new Uint8Array(outputData)], {
          type: format === "ios" ? "audio/mp4" : "audio/mpeg",
        });
        const url = URL.createObjectURL(blob);
        const anchor = document.createElement("a");

        anchor.style.display = "none";
        anchor.href = url;
        anchor.download = `ringtone-${Date.now()}.${format === "ios" ? "m4r" : "mp3"}`;
        document.body.appendChild(anchor);
        anchor.click();

        window.setTimeout(() => {
          window.URL.revokeObjectURL(url);
          document.body.removeChild(anchor);
        }, 100);

        await ffmpeg.deleteFile("input.wav");
        await ffmpeg.deleteFile(outputFilename);
      } catch (error) {
        console.error("FFmpeg conversion error:", error);
        setMessageKind("default");
        setMessage("Export failed. Please try again.");
      } finally {
        setExportingFormat(null);
      }
    },
    [
      ffmpegLoaded,
      ffmpegRef,
      focusMessage,
      regionsRef,
      setMessage,
      setMessageKind,
      wavesurferRef,
    ],
  );

  return { exportingFormat, handleExport };
}
