"use client";

import { FFmpeg } from "@ffmpeg/ffmpeg";
import { useEffect, useRef, useState } from "react";

interface UseFFmpegOptions {
  onLoadError: () => void;
  onLoadSuccess: () => void;
}

export default function useFFmpeg({
  onLoadError,
  onLoadSuccess,
}: UseFFmpegOptions) {
  const ffmpegRef = useRef<FFmpeg | null>(null);
  const [ffmpegLoaded, setFFmpegLoaded] = useState<boolean>(false);
  const [ffmpegProgress, setFFmpegProgress] = useState<number>(0);

  useEffect(() => {
    const loadFFmpeg = async () => {
      if (ffmpegRef.current) {
        return;
      }

      try {
        const ffmpeg = new FFmpeg();
        ffmpegRef.current = ffmpeg;
        setFFmpegProgress(0.08);

        ffmpeg.on("log", ({ message }) => {
          console.log("[FFmpeg]", message);
        });

        ffmpeg.on("progress", ({ progress }) => {
          setFFmpegProgress((current) => Math.max(current, progress));
        });

        await ffmpeg.load();
        setFFmpegProgress(1);
        setFFmpegLoaded(true);
        onLoadSuccess();
      } catch (error) {
        console.error("Failed to load FFmpeg", error);
        onLoadError();
      }
    };

    loadFFmpeg();
  }, [onLoadError, onLoadSuccess]);

  useEffect(() => {
    if (ffmpegLoaded) {
      return;
    }

    const timer = window.setInterval(() => {
      setFFmpegProgress((current) => {
        if (current >= 0.92) {
          return current;
        }

        return Math.min(0.92, current + 0.04);
      });
    }, 500);

    return () => {
      window.clearInterval(timer);
    };
  }, [ffmpegLoaded]);

  return { ffmpegLoaded, ffmpegProgress, ffmpegRef };
}
